protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator" instead of "$type")
    // so existing documents and direct SQL queries (WHERE c.Discriminator = ...) keep working.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123" instead of "123")
    // so point-reads against existing 500K documents continue to work.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

